import unittest
import encoder

class TestConstraint(unittest.TestCase):
    def test_no_base64_import(self):
        with open('encoder.py', 'r') as f:
            content = f.read()
            self.assertNotIn('import base64', content)
            self.assertNotIn('from base64', content)

    def test_encoding(self):
        # 'Man' -> 'TWFu'
        self.assertEqual(encoder.encode_plain(b'Man'), 'TWFu')

if __name__ == '__main__':
    unittest.main()
